mapper.select:
SELECT CM.PRDCT_CD, B.FUND_CLS_CD, -- 클래스펀드코드 F.ASSCTN_FUND_NM, -- 협회(클래스)펀드명 F.TRAN_WAY, -- 거래방식 F.CNTRCT_PRD_STRT, -- 계약시작일 F.CNTRCT_PRD_END, -- 계약종료일 C.PRVSN_MK1 AS PRVSN_MK1_FILENM, --집합투자규약 C.PRVSN_MK2 AS PRVSN_MK2_FILENM, -- 투자설명서 C.PRVSN_MK3 AS PRVSN_MK3_FILENM, -- 간이투자설명서 C.PRVSN_MK4 AS PRVSN_MK4_FILENM, -- 외국집합투자증권 COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF5' AND SUB_CD = F.FUND_CLS1 AND USE_IND='Y'), '') AS FUND_CLS1_NM, COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF6' AND SUB_CD = F.FUND_CLS2 AND USE_IND='Y'), '') AS FUND_CLS2_NM, COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF7' AND SUB_CD = F.FUND_CLS3 AND USE_IND='Y'), '') AS FUND_CLS3_NM FROM MA30_FNANCL_PRDCT_CMMN CM INNER JOIN MA30_FNANCL_PRDCT_FUND B ON CM.PRDCT_CD = B.PRDCT_CD INNER JOIN FUND_PRDCT F ON B.FUND_CLS_CD = F.FUND_CD LEFT JOIN (SELECT PRV3.PRDCT_CD, MAX(PRVSN_MK1) AS PRVSN_MK1 ,MAX(PRVSN_MK2) AS PRVSN_MK2, MAX(PRVSN_MK3) AS PRVSN_MK3, MAX(PRVSN_MK4) AS PRVSN_MK4 FROM (SELECT PRV2.PRDCT_CD, CASE WHEN PRV1.PRVSN_MK = 'ATF011' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK1", CASE WHEN PRV1.PRVSN_MK = 'ATF012' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK2", CASE WHEN PRV1.PRVSN_MK = 'ATF013' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK3", CASE WHEN PRV1.PRVSN_MK = 'ATF014' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK4" FROM MA30_PRDCT_PRVSN_MGT PRV1 INNER JOIN MA30_FNANCL_PRDCT_ATT_FILE PRV2 ON PRV1.PRVSN_CD = PRV2.PRVSN_CD WHERE PRV1.LOCTN_CD = 'LN1001' AND PRV1.USE_YN = 'Y' AND PRV1.PRVSN_MK IN ('ATF011','ATF012','ATF013','ATF014') ) PRV3 GROUP BY PRV3.PRDCT_CD) C ON CM.PRDCT_CD = C.PRDCT_CD WHERE CM.PRDCT_LANG_CD = 'LN1001' -- 게시언어구분 AND F.SALE_FLG = 'Y' AND CM.APP_STATUS = 'PF4005' -- 승인상태(승인완료) AND CM.PRDCT_MK_CD = 'BP1006' -- 상품구분코드 AND (VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMMDDHH24') BETWEEN COALESCE(CM.SALE_START_DT,'20190101')||COALESCE(CM.SALE_START_TM,'00') AND COALESCE(CM.SALE_END_DT,'20190101')||COALESCE(CM.SALE_END_TM,'00') ) AND B.FUND_CLS_CD IN
#{item}
ORDER BY CM.REGIST_DT DESC WITH UR

SELECT CM.PRDCT_CD, B.FUND_CLS_CD, -- 클래스펀드코드 F.ASSCTN_FUND_NM, -- 협회(클래스)펀드명 F.TRAN_WAY, -- 거래방식 F.CNTRCT_PRD_STRT, -- 계약시작일 F.CNTRCT_PRD_END, -- 계약종료일 C.PRVSN_MK1 AS PRVSN_MK1_FILENM, --집합투자규약 C.PRVSN_MK2 AS PRVSN_MK2_FILENM, -- 투자설명서 C.PRVSN_MK3 AS PRVSN_MK3_FILENM, -- 간이투자설명서 C.PRVSN_MK4 AS PRVSN_MK4_FILENM, -- 외국집합투자증권 C.PRVSN_MK5 AS PRVSN_MK5_FILENM, -- 사모집합투자증권 핵심요약상품설명서 C.PRVSN_MK6 AS PRVSN_MK6_FILENM, -- 사모집합투자증권 핵심상품설명서 COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF5' AND SUB_CD = F.FUND_CLS1 AND USE_IND='Y'), '') AS FUND_CLS1_NM, COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF6' AND SUB_CD = F.FUND_CLS2 AND USE_IND='Y'), '') AS FUND_CLS2_NM, COALESCE((SELECT CD_NM FROM SUB_CD WHERE CMMN_CD = 'PF7' AND SUB_CD = F.FUND_CLS3 AND USE_IND='Y'), '') AS FUND_CLS3_NM FROM MA30_FNANCL_PRDCT_CMMN CM INNER JOIN MA30_FNANCL_PRDCT_FUND B ON CM.PRDCT_CD = B.PRDCT_CD INNER JOIN FUND_PRDCT F ON B.FUND_CLS_CD = F.FUND_CD LEFT JOIN (SELECT PRV3.PRDCT_CD, MAX(PRVSN_MK1) AS PRVSN_MK1 ,MAX(PRVSN_MK2) AS PRVSN_MK2, MAX(PRVSN_MK3) AS PRVSN_MK3, MAX(PRVSN_MK4) AS PRVSN_MK4, MAX(PRVSN_MK5) AS PRVSN_MK5, MAX(PRVSN_MK6) AS PRVSN_MK6 FROM (SELECT PRV2.PRDCT_CD, CASE WHEN PRV1.PRVSN_MK = 'ATF011' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK1", CASE WHEN PRV1.PRVSN_MK = 'ATF012' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK2", CASE WHEN PRV1.PRVSN_MK = 'ATF013' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK3", CASE WHEN PRV1.PRVSN_MK = 'ATF014' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK4", CASE WHEN PRV1.PRVSN_MK = 'ATF018' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK5", CASE WHEN PRV1.PRVSN_MK = 'ATF017' THEN PRV1.ATT_FILE_NM ELSE NULL END AS "PRVSN_MK6" FROM MA30_PRDCT_PRVSN_MGT PRV1 INNER JOIN MA30_FNANCL_PRDCT_ATT_FILE PRV2 ON PRV1.PRVSN_CD = PRV2.PRVSN_CD WHERE PRV1.LOCTN_CD = 'LN1001' AND PRV1.USE_YN = 'Y' AND PRV1.PRVSN_MK IN ('ATF011','ATF012','ATF013','ATF014','ATF018','ATF017') ) PRV3 GROUP BY PRV3.PRDCT_CD) C ON CM.PRDCT_CD = C.PRDCT_CD WHERE CM.PRDCT_LANG_CD = 'LN1001' -- 게시언어구분 AND F.SALE_FLG = 'Y' AND CM.APP_STATUS = 'PF4005' -- 승인상태(승인완료) AND CM.PRDCT_MK_CD = 'BP1006' -- 상품구분코드 AND (VARCHAR_FORMAT(CURRENT TIMESTAMP, 'YYYYMMDDHH24') BETWEEN COALESCE(CM.SALE_START_DT,'20190101')||COALESCE(CM.SALE_START_TM,'00') AND COALESCE(CM.SALE_END_DT,'20190101')||COALESCE(CM.SALE_END_TM,'00') ) AND B.FUND_CLS_CD IN
#{item}
ORDER BY CM.REGIST_DT DESC WITH UR
